import { IMessageComposer } from '@nitrots/nitro-renderer';

export class MythicalBlueprintCraftComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(sessionId: number, blueprintItemId: number)
{
// Must match MythicalBlueprintCraftEvent.java order EXACTLY:
// sessionId, blueprintItemId
this._data = [
sessionId,
blueprintItemId
];

console.log('Packet MythicalBlueprintCraftComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}